arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 0);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" string to a boolean Label column
var labelKeys = new[] { "Yes", "No" };
var labelValues = new[] { true, false };

var pipeline = mlContext.Transforms.Conversion.MapValue(
        "Label", new[] { new KeyValuePair<string, bool>("Yes", true),
                         new KeyValuePair<string, bool>("No", false) },
        inputColumnName: nameof(CustomerData.Churned))
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded",
        nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(rawData);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API – POST to /predict with Age, Income, Region, PurchaseHistory");

app.MapPost("/predict", (CustomerInput input) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
        Churned = string.Empty
    };

    var prediction = predictionEngine.Predict(data);

    return Results.Ok(new
    {
        willChurn = prediction.WillChurn,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

